import { useEffect, useRef } from 'react';
import { Renderer, Triangle, Program, Mesh } from 'ogl';
import './Prism.css';

interface PrismProps {
    height?: number;
    baseWidth?: number;
    animationType?: string;
    glow?: number;
    offset?: { x: number; y: number };
    noise?: number;
    transparent?: boolean;
    scale?: number;
    hueShift?: number;
    colorFrequency?: number;
    hoverStrength?: number;
    inertia?: number;
    bloom?: number;
    suspendWhenOffscreen?: boolean;
    timeScale?: number;
}

const Prism = ({
    height = 3.5,
    baseWidth = 5.5,
    animationType = 'rotate',
    glow = 1.2,
    offset = { x: 0, y: 0 },
    noise = 0.05, // reduced from 0.5 to stop flicker
    transparent = true,
    scale = 6.5,
    hueShift = 0.5, // Shifted to match the gold/primary color
    colorFrequency = 1,
    hoverStrength = 2,
    inertia = 0.05,
    bloom = 1.5,
    suspendWhenOffscreen = false,
    timeScale = 0.5
}: PrismProps) => {
    const containerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const container = containerRef.current;
        if (!container) return;

        const H = Math.max(0.001, height);
        const BW = Math.max(0.001, baseWidth);
        const BASE_HALF = BW * 0.5;
        const GLOW = Math.max(0.0, glow);
        const NOISE = Math.max(0.0, noise);
        const offX = offset?.x ?? 0;
        const offY = offset?.y ?? 0;
        const SAT = transparent ? 1.5 : 1;
        const SCALE = Math.max(0.001, scale);
        const HUE = hueShift || 0;
        const CFREQ = Math.max(0.0, colorFrequency || 1);
        const BLOOM = Math.max(0.0, bloom || 1);
        const RSX = 1;
        const RSY = 1;
        const RSZ = 1;
        const TS = Math.max(0, timeScale || 1);
        const HOVSTR = Math.max(0, hoverStrength || 1);
        const INERT = Math.max(0, Math.min(1, inertia || 0.12));

        const dpr = Math.min(2, window.devicePixelRatio || 1);
        const renderer = new Renderer({
            dpr,
            alpha: transparent,
            antialias: false
        });
        const gl = renderer.gl;
        gl.disable(gl.DEPTH_TEST);
        gl.disable(gl.CULL_FACE);
        gl.disable(gl.BLEND);

        Object.assign(gl.canvas.style, {
            position: 'absolute',
            inset: '0',
            width: '100%',
            height: '100%',
            display: 'block',
            opacity: '0.6', // Requested opacity 60%
            pointerEvents: 'none' // Ensure it doesn't block interactions
        });
        container.appendChild(gl.canvas);

        const vertex = /* glsl */ `
      attribute vec2 position;
      void main() {
        gl_Position = vec4(position, 0.0, 1.0);
      }
    `;

        const fragment = /* glsl */ `
      precision highp float;

      uniform vec2  iResolution;
      uniform float iTime;

      uniform float uHeight;
      uniform float uBaseHalf;
      uniform mat3  uRot;
      uniform int   uUseBaseWobble;
      uniform float uGlow;
      uniform vec2  uOffsetPx;
      uniform float uNoise;
      uniform float uSaturation;
      uniform float uScale;
      uniform float uHueShift;
      uniform float uColorFreq;
      uniform float uBloom;
      uniform float uCenterShift;
      uniform float uInvBaseHalf;
      uniform float uInvHeight;
      uniform float uMinAxis;
      uniform float uPxScale;
      uniform float uTimeScale;

      vec4 tanh4(vec4 x){
        vec4 e2x = exp(2.0*x);
        return (e2x - 1.0) / (e2x + 1.0);
      }

      float rand(vec2 co){
        return fract(sin(dot(co, vec2(12.9898, 78.233))) * 43758.5453123);
      }

      float sdOctaAnisoInv(vec3 p){
        vec3 q = vec3(abs(p.x) * uInvBaseHalf, abs(p.y) * uInvHeight, abs(p.z) * uInvBaseHalf);
        float m = q.x + q.y + q.z - 1.0;
        return m * uMinAxis * 0.5773502691896258;
      }

      float sdPyramidUpInv(vec3 p){
        float oct = sdOctaAnisoInv(p);
        float halfSpace = -p.y;
        return max(oct, halfSpace);
      }

      mat3 hueRotation(float a){
        float c = cos(a), s = sin(a);
        mat3 W = mat3(
          0.299, 0.587, 0.114,
          0.299, 0.587, 0.114,
          0.299, 0.587, 0.114
        );
        mat3 U = mat3(
           0.701, -0.587, -0.114,
          -0.299,  0.413, -0.114,
          -0.300, -0.588,  0.886
        );
        mat3 V = mat3(
           0.168, -0.331,  0.500,
           0.328,  0.035, -0.500,
          -0.497,  0.296,  0.201
        );
        return W + U * c + V * s;
      }

      void main(){
        vec2 f = (gl_FragCoord.xy - 0.5 * iResolution.xy - uOffsetPx) * uPxScale;

        float z = 5.0;
        float d = 0.0;

        vec3 p;
        vec4 o = vec4(0.0);

        float centerShift = uCenterShift;
        float cf = uColorFreq;

        mat2 wob = mat2(1.0);
        if (uUseBaseWobble == 1) {
          float t = iTime * uTimeScale;
          float c0 = cos(t + 0.0);
          float c1 = cos(t + 33.0);
          float c2 = cos(t + 11.0);
          wob = mat2(c0, c1, c2, c0);
        }

        const int STEPS = 100;
        for (int i = 0; i < STEPS; i++) {
          p = vec3(f, z);
          p.xz = p.xz * wob;
          p = uRot * p;
          vec3 q = p;
          q.y += centerShift;
          d = 0.1 + 0.2 * abs(sdPyramidUpInv(q));
          z -= d;
          o += (sin((p.y + z) * cf + vec4(0.0, 1.0, 2.0, 3.0)) + 1.0) / d;
        }

        o = tanh4(o * o * (uGlow * uBloom) / 1e5);

        vec3 col = o.rgb;
        float n = rand(gl_FragCoord.xy + vec2(iTime));
        col += (n - 0.5) * uNoise;
        col = clamp(col, 0.0, 1.0);

        float L = dot(col, vec3(0.2126, 0.7152, 0.0722));
        col = clamp(mix(vec3(L), col, uSaturation), 0.0, 1.0);

        if(abs(uHueShift) > 0.0001){
          col = clamp(hueRotation(uHueShift) * col, 0.0, 1.0);
        }

        // Apply dark gold tint logic here
        vec3 darkGold = vec3(0.65, 0.45, 0.15); // Adjust for specific gold tint
        col = mix(col, col * darkGold, 0.8); // Blend with gold tint

        gl_FragColor = vec4(col, o.a);
      }
    `;

        const geometry = new Triangle(gl);
        const iResBuf = new Float32Array(2);
        const offsetPxBuf = new Float32Array(2);

        const program = new Program(gl, {
            vertex,
            fragment,
            uniforms: {
                iResolution: { value: iResBuf },
                iTime: { value: 0 },
                uHeight: { value: H },
                uBaseHalf: { value: BASE_HALF },
                uUseBaseWobble: { value: 1 },
                uRot: { value: new Float32Array([1, 0, 0, 0, 1, 0, 0, 0, 1]) },
                uGlow: { value: GLOW },
                uOffsetPx: { value: offsetPxBuf },
                uNoise: { value: NOISE },
                uSaturation: { value: SAT },
                uScale: { value: SCALE },
                uHueShift: { value: HUE },
                uColorFreq: { value: CFREQ },
                uBloom: { value: BLOOM },
                uCenterShift: { value: H * 0.25 },
                uInvBaseHalf: { value: 1 / BASE_HALF },
                uInvHeight: { value: 1 / H },
                uMinAxis: { value: Math.min(BASE_HALF, H) },
                uPxScale: {
                    value: 1 / ((gl.drawingBufferHeight || 1) * 0.1 * SCALE)
                },
                uTimeScale: { value: TS }
            }
        });

        const mesh = new Mesh(gl, { geometry, program });

        const resize = () => {
            const w = container.clientWidth || 1;
            const h = container.clientHeight || 1;
            renderer.setSize(w, h);
            iResBuf[0] = gl.drawingBufferWidth;
            iResBuf[1] = gl.drawingBufferHeight;
            offsetPxBuf[0] = offX * dpr;
            offsetPxBuf[1] = offY * dpr;
            program.uniforms.uPxScale.value = 1 / ((gl.drawingBufferHeight || 1) * 0.1 * SCALE);
        };
        const ro = new ResizeObserver(resize);
        ro.observe(container);
        resize();

        const rotBuf = new Float32Array(9);
        const setMat3FromEuler = (yawY: number, pitchX: number, rollZ: number, out: Float32Array) => {
            const cy = Math.cos(yawY),
                sy = Math.sin(yawY);
            const cx = Math.cos(pitchX),
                sx = Math.sin(pitchX);
            const cz = Math.cos(rollZ),
                sz = Math.sin(rollZ);
            const r00 = cy * cz + sy * sx * sz;
            const r01 = -cy * sz + sy * sx * cz;
            const r02 = sy * cx;

            const r10 = cx * sz;
            const r11 = cx * cz;
            const r12 = -sx;

            const r20 = -sy * cz + cy * sx * sz;
            const r21 = sy * sz + cy * sx * cz;
            const r22 = cy * cx;

            out[0] = r00;
            out[1] = r10;
            out[2] = r20;
            out[3] = r01;
            out[4] = r11;
            out[5] = r21;
            out[6] = r02;
            out[7] = r12;
            out[8] = r22;
            return out;
        };

        const NOISE_IS_ZERO = NOISE < 1e-6;
        let raf = 0;
        const t0 = performance.now();
        const startRAF = () => {
            if (raf) return;
            raf = requestAnimationFrame(render);
        };
        const stopRAF = () => {
            if (!raf) return;
            cancelAnimationFrame(raf);
            raf = 0;
        };

        const rnd = () => Math.random();
        const wX = (0.3 + rnd() * 0.6) * RSX;
        const wY = (0.2 + rnd() * 0.7) * RSY;
        const wZ = (0.1 + rnd() * 0.5) * RSZ;
        const phX = rnd() * Math.PI * 2;
        const phZ = rnd() * Math.PI * 2;

        let yaw = 0,
            pitch = 0,
            roll = 0;
        let targetYaw = 0,
            targetPitch = 0;
        const lerp = (a: number, b: number, t: number) => a + (b - a) * t;

        const pointer = { x: 0, y: 0, inside: true };
        const onMove = (e: MouseEvent) => {
            const ww = Math.max(1, window.innerWidth);
            const wh = Math.max(1, window.innerHeight);
            const cx = ww * 0.5;
            const cy = wh * 0.5;
            const nx = (e.clientX - cx) / (ww * 0.5);
            const ny = (e.clientY - cy) / (wh * 0.5);
            pointer.x = Math.max(-1, Math.min(1, nx));
            pointer.y = Math.max(-1, Math.min(1, ny));
            pointer.inside = true;
        };
        const onLeave = () => {
            pointer.inside = false;
        };
        const onBlur = () => {
            pointer.inside = false;
        };

        let onPointerMove: ((e: MouseEvent) => void) | null = null;
        if (animationType === 'hover') {
            onPointerMove = (e: MouseEvent) => {
                onMove(e);
                startRAF();
            };
            window.addEventListener('pointermove', onPointerMove, { passive: true });
            window.addEventListener('mouseleave', onLeave);
            window.addEventListener('blur', onBlur);
            program.uniforms.uUseBaseWobble.value = 0;
        } else if (animationType === '3drotate') {
            program.uniforms.uUseBaseWobble.value = 0;
        } else {
            program.uniforms.uUseBaseWobble.value = 1;
        }

        const render = (t: number) => {
            const time = (t - t0) * 0.001;
            program.uniforms.iTime.value = time;

            let continueRAF = true;

            if (animationType === 'hover') {
                const maxPitch = 0.6 * HOVSTR;
                const maxYaw = 0.6 * HOVSTR;
                targetYaw = (pointer.inside ? -pointer.x : 0) * maxYaw;
                targetPitch = (pointer.inside ? pointer.y : 0) * maxPitch;
                const prevYaw = yaw;
                const prevPitch = pitch;
                const prevRoll = roll;
                yaw = lerp(prevYaw, targetYaw, INERT);
                pitch = lerp(prevPitch, targetPitch, INERT);
                roll = lerp(prevRoll, 0, 0.1);
                program.uniforms.uRot.value = setMat3FromEuler(yaw, pitch, roll, rotBuf);

                if (NOISE_IS_ZERO) {
                    const settled =
                        Math.abs(yaw - targetYaw) < 1e-4 && Math.abs(pitch - targetPitch) < 1e-4 && Math.abs(roll) < 1e-4;
                    if (settled) continueRAF = false;
                }
            } else if (animationType === '3drotate') {
                const tScaled = time * TS;
                yaw = tScaled * wY;
                pitch = Math.sin(tScaled * wX + phX) * 0.6;
                roll = Math.sin(tScaled * wZ + phZ) * 0.5;
                program.uniforms.uRot.value = setMat3FromEuler(yaw, pitch, roll, rotBuf);
                if (TS < 1e-6) continueRAF = false;
            } else {
                rotBuf[0] = 1;
                rotBuf[1] = 0;
                rotBuf[2] = 0;
                rotBuf[3] = 0;
                rotBuf[4] = 1;
                rotBuf[5] = 0;
                rotBuf[6] = 0;
                rotBuf[7] = 0;
                rotBuf[8] = 1;
                program.uniforms.uRot.value = rotBuf;
                if (TS < 1e-6) continueRAF = false;
            }

            renderer.render({ scene: mesh });
            if (continueRAF) {
                raf = requestAnimationFrame(render);
            } else {
                raf = 0;
            }
        };

        if (suspendWhenOffscreen) {
            const io = new IntersectionObserver((entries) => {
                const vis = entries.some(e => e.isIntersecting);
                if (vis) startRAF();
                else stopRAF();
            });
            io.observe(container);
            startRAF();
            (container as any).__prismIO = io;
        } else {
            startRAF();
        }

        return () => {
            stopRAF();
            ro.disconnect();
            if (animationType === 'hover') {
                if (onPointerMove) window.removeEventListener('pointermove', onPointerMove);
                window.removeEventListener('mouseleave', onLeave);
                window.removeEventListener('blur', onBlur);
            }
            if (suspendWhenOffscreen) {
                const io = (container as any).__prismIO;
                if (io) io.disconnect();
                delete (container as any).__prismIO;
            }
            if (gl.canvas.parentElement === container) container.removeChild(gl.canvas);
        };
    }, [
        height,
        baseWidth,
        animationType,
        glow,
        noise,
        offset?.x,
        offset?.y,
        scale,
        transparent,
        hueShift,
        colorFrequency,
        timeScale,
        hoverStrength,
        inertia,
        bloom,
        suspendWhenOffscreen
    ]);

    return <div className="prism-container" ref={containerRef} />;
};

export default Prism;

import React, { useEffect, useRef, ReactNode } from 'react';
import './ScrollStack.css';

interface ScrollStackItemProps {
    children: ReactNode;
    itemClassName?: string;
    style?: React.CSSProperties;
}

export const ScrollStackItem = ({ children, itemClassName = '', style }: ScrollStackItemProps) => (
    <div className={`scroll-stack-card-wrapper ${itemClassName}`.trim()} style={style}>
        {children}
    </div>
);

interface ScrollStackProps {
    children: ReactNode;
    className?: string;
    itemDistance?: number;
    itemScale?: number;
    itemStackDistance?: number;
    stackPosition?: string;
    scaleEndPosition?: string;
    baseScale?: number;
    scaleDuration?: number;
    rotationAmount?: number;
    blurAmount?: number;
    useWindowScroll?: boolean;
    onStackComplete?: () => void;
}

const ScrollStack = ({
    children,
    className = '',
    itemDistance = 40,
    itemScale = 0.05,
    itemStackDistance = 20,
}: ScrollStackProps) => {
    const containerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleScroll = () => {
            if (!containerRef.current) return;
            const cards = containerRef.current.querySelectorAll('.scroll-stack-card-wrapper');

            cards.forEach((card, index) => {
                const rect = card.getBoundingClientRect();
                const stickyTop = 150 + index * itemStackDistance;

                // A more robust way to measure scroll progress:
                // We find out where this card is located within the entire document flow.
                // We use getBoundingClientRect().top + window.scrollY to get absolute page offset.
                // The element starts sticking when window.scrollY reaches (absoluteTop - stickyTop).
                // But we ONLY want it to blur and scale when the NEXT card starts pushing up over it.
                // The next card will hit its sticky point approximately `40vh` after this card does,
                // because we added a 40vh margin-bottom to each card wrapper.

                const cardHeight = rect.height || 400;

                // If it's the last card, it should never blur.
                const isLast = index === cards.length - 1;

                // Rect.top gets stuck at stickyTop. 
                // We can see how far we've over-scrolled by looking at how negative (rect.top - stickyTop) *would* be
                // if position wasn't sticky... Oh wait, sticky fixes rect.top.
                // We must use the container or the parent element offsets!

                // Let's use the wrapper's top relative to the viewport.
                // If it equals stickyTop, it's pinned.
                // How far is the user scrolling WHILE it's pinned? 
                // We can look at the element's top position before sticky takes over.
                // HTMLElement.offsetTop gives top position relative to offsetParent.
                const offsetTop = (card as HTMLElement).offsetTop;
                // offsetParent is likely the `.flex.flex-col.relative` container.
                // Get the container's absolute top relative to the page:
                const containerAbsoluteTop = (containerRef.current?.getBoundingClientRect().top ?? 0) + window.scrollY;

                const cardAbsoluteTop = containerAbsoluteTop + offsetTop;

                // The point at which THIS card becomes sticky
                const stickStartScroll = cardAbsoluteTop - stickyTop;

                // The point at which the NEXT card becomes sticky (roughly stickStartScroll + 40vh for the margin + card height)
                // Let's just use a fixed scroll distance for the transition, e.g., 400px of scrolling AFTER it hits the sticky point.

                const scrollPassedStickPoint = window.scrollY - stickStartScroll;

                if (scrollPassedStickPoint > 0 && !isLast) {
                    // Only start blurring when the user scrolls down further by e.g. 50px
                    const transitionStart = 50;
                    const transitionEnd = cardHeight;

                    let progress = 0;
                    if (scrollPassedStickPoint > transitionStart) {
                        progress = Math.min(1, (scrollPassedStickPoint - transitionStart) / transitionEnd);
                    }

                    const scale = 1 - (progress * itemScale * 2);

                    const innerChild = (card as HTMLElement).firstElementChild as HTMLElement;
                    if (innerChild) {
                        innerChild.style.transform = `scale(${scale})`;
                        innerChild.style.opacity = progress > 0.8 ? `${1 - (progress - 0.8) * 2}` : `1`;
                    }
                } else {
                    const innerChild = (card as HTMLElement).firstElementChild as HTMLElement;
                    if (innerChild) {
                        innerChild.style.transform = `scale(1)`;
                        innerChild.style.opacity = `1`;
                    }
                }
            });
        };

        window.addEventListener('scroll', handleScroll, { passive: true });
        // Initial call
        handleScroll();

        return () => {
            window.removeEventListener('scroll', handleScroll);
        };
    }, [itemStackDistance, itemScale]);

    return (
        <div className={`relative w-full ${className}`.trim()} ref={containerRef}>
            <div className="flex flex-col relative">
                {React.Children.map(children, (child, index) => {
                    if (React.isValidElement(child)) {
                        const isLast = index === React.Children.count(children) - 1;
                        return React.cloneElement(child as React.ReactElement<any>, {
                            style: { marginBottom: isLast ? '0px' : '40vh' }
                        });
                    }
                    return child;
                })}
            </div>
        </div>
    );
};

export default ScrollStack;

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const badgeVariants = cva(
  "inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2",
  {
    variants: {
      variant: {
        default: "border-transparent bg-primary text-primary-foreground hover:bg-primary/80",
        secondary: "border-transparent bg-secondary text-secondary-foreground hover:bg-secondary/80",
        destructive: "border-transparent bg-destructive text-destructive-foreground hover:bg-destructive/80",
        outline: "text-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
);

export interface BadgeProps extends React.HTMLAttributes<HTMLDivElement>, VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return <div className={cn(badgeVariants({ variant }), className)} {...props} />;
}

export { Badge, badgeVariants };

import * as React from "react";
import { Slot } from "@radix-ui/react-slot";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive: "bg-destructive text-destructive-foreground hover:bg-destructive/90",
        outline: "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
        secondary: "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-10 px-4 py-2",
        sm: "h-9 rounded-md px-3",
        lg: "h-11 rounded-md px-8",
        icon: "h-10 w-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button";
    return <Comp className={cn(buttonVariants({ variant, size, className }))} ref={ref} {...props} />;
  },
);
Button.displayName = "Button";

export { Button, buttonVariants };

import * as React from "react";
import { type DialogProps } from "@radix-ui/react-dialog";
import { Command as CommandPrimitive } from "cmdk";
import { Search } from "lucide-react";

import { cn } from "@/lib/utils";
import { Dialog, DialogContent } from "@/components/ui/dialog";

const Command = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive>
>(({ className, ...props }, ref) => (
  <CommandPrimitive
    ref={ref}
    className={cn(
      "flex h-full w-full flex-col overflow-hidden rounded-md bg-popover text-popover-foreground",
      className,
    )}
    {...props}
  />
));
Command.displayName = CommandPrimitive.displayName;

interface CommandDialogProps extends DialogProps {}

const CommandDialog = ({ children, ...props }: CommandDialogProps) => {
  return (
    <Dialog {...props}>
      <DialogContent className="overflow-hidden p-0 shadow-lg">
        <Command className="[&_[cmdk-group-heading]]:px-2 [&_[cmdk-group-heading]]:font-medium [&_[cmdk-group-heading]]:text-muted-foreground [&_[cmdk-group]:not([hidden])_~[cmdk-group]]:pt-0 [&_[cmdk-group]]:px-2 [&_[cmdk-input-wrapper]_svg]:h-5 [&_[cmdk-input-wrapper]_svg]:w-5 [&_[cmdk-input]]:h-12 [&_[cmdk-item]]:px-2 [&_[cmdk-item]]:py-3 [&_[cmdk-item]_svg]:h-5 [&_[cmdk-item]_svg]:w-5">
          {children}
        </Command>
      </DialogContent>
    </Dialog>
  );
};

